const mercariBtn={display:'flex',alignItems:'center',justifyContent:'center',padding:'12px 16px',fontSize:SZ.sm,fontWeight:600,color:T.textHi,background:T.surface2,border:"1px solid ".concat(T.border2),borderRadius:12,textDecoration:'none',cursor:'pointer',fontFamily:'inherit'};const ebayLinkBtn={display:'flex',alignItems:'center',justifyContent:'center',padding:'10px 14px',textAlign:'center',background:T.surface2,border:"1px solid ".concat(T.borderHi),color:T.cyan,borderRadius:10,fontSize:SZ.sm,fontFamily:T.fontDisplay,fontWeight:600,letterSpacing:'0.08em',textTransform:'uppercase',textDecoration:'none'};// Convert between any two currencies via THB as the bridge currency.
