const DEFAULT_FX_FALLBACK={THB:1,USD:0.0286,PHP:1.66,JPY:4.32,MYR:0.128,SGD:0.0383};// ----------------------------------------------------------
// VariantPicker — grid of SAMPLE images for every known rarity of a code.
