const VAULT_GRADE_OPTIONS=['Raw','PSA 10','PSA 9','BGS 10','BGS 10 BL','BGS 9.5','CGC 10','CGC 9.5','ARS 10','SGC 10'];// ImageLightbox — fullscreen image viewer with zoom controls.
// SCN6: initialZoom prop lets corner thumbnails open at 300%. The user can
